import{_ as r}from"./chunks/sign-up.B6w_QBvP.js";import{_ as o}from"./chunks/dashboard.B0ClCvQC.js";import{_ as a,o as s,c as e,a2 as n}from"./chunks/framework.BflysNKA.js";const d="/images/tutorial/registration.gif",i="/images/tutorial/sign-in.png",g="/images/tutorial/sidebar.png",P=JSON.parse('{"title":"注册与登录","description":"","frontmatter":{},"headers":[],"relativePath":"guide/registration.md","filePath":"guide/registration.md","lastUpdated":1780487132000}'),l={name:"guide/registration.md"};function p(h,t,c,u,b,m){return s(),e("div",null,[...t[0]||(t[0]=[n('<h1 id="注册与登录" tabindex="-1">注册与登录 <a class="header-anchor" href="#注册与登录" aria-label="Permalink to &quot;注册与登录&quot;">​</a></h1><p>注册一个账号后，你就能在控制台里充值、创建 API 密钥、查看模型价格和调用日志。</p><p>入口：<strong><a href="https://xiaolan1.cn" target="_blank" rel="noreferrer">小蓝中转站 控制台</a></strong></p><blockquote><p>整个注册过程不需要邮箱、不需要手机号，只要想一个用户名和密码即可。下面这张动图是完整流程，看不清的步骤再往下看分解说明。</p></blockquote><p><img src="'+d+'" alt="注册流程动图：填写信息 → 勾选人机验证 → 创建账户 → 前往登录"></p><h2 id="第一步-注册账号" tabindex="-1">第一步：注册账号 <a class="header-anchor" href="#第一步-注册账号" aria-label="Permalink to &quot;第一步：注册账号&quot;">​</a></h2><p>打开 <a href="https://xiaolan1.cn" target="_blank" rel="noreferrer">小蓝中转站 官网</a>，点右上角 <strong>注册</strong>，或直接访问 <a href="https://xiaolan1.cn/sign-up" target="_blank" rel="noreferrer">注册页</a>。</p><p>页面左侧是产品介绍，<strong>右侧白色卡片</strong>才是要填的注册表单：</p><p><img src="'+r+'" alt="注册页面：用户名、密码、确认密码三个输入框，再勾选人机验证，最后点创建账户"></p><p>按图中编号从上往下填：</p><table tabindex="0"><thead><tr><th>编号</th><th>字段</th><th>怎么填</th></tr></thead><tbody><tr><td>①</td><td><strong>用户名</strong></td><td>自己取，建议用英文、数字或短横线（如 <code>xiaolan-demo-user</code>）。登录时要用，注册后不能改。</td></tr><tr><td>②</td><td><strong>密码</strong></td><td>8–20 个字符，建议混合大小写字母和数字。</td></tr><tr><td>③</td><td><strong>确认密码</strong></td><td>再输入一次，和上面完全一致。</td></tr><tr><td>④</td><td><strong>人机验证</strong></td><td>点一下方框，等它自动变成「人机验证已完成」（绿色对勾）即可，不用输入任何字符。</td></tr><tr><td>⑤</td><td><strong>创建账户</strong></td><td>四项都就绪后点这个黑色按钮。</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">不需要邮箱</p><p>默认注册<strong>只要用户名和密码</strong>，没有邮箱栏，也不会收到验证邮件。只有当站点单独开启了「邮箱验证」时，页面才会多出邮箱和验证码栏——如果你的页面没有这两栏，属于正常情况。</p></div><p>点 <strong>创建账户</strong> 后，会提示「账户创建成功」并自动跳转到登录页。</p><h2 id="第二步-登录" tabindex="-1">第二步：登录 <a class="header-anchor" href="#第二步-登录" aria-label="Permalink to &quot;第二步：登录&quot;">​</a></h2><p>在 <a href="https://xiaolan1.cn/sign-in" target="_blank" rel="noreferrer">登录页</a> 用刚才的用户名和密码登录：</p><p><img src="'+i+'" alt="登录页面：填用户名和密码，勾选下方的人机验证，再点登录"></p><p>注意这个主题的<strong>顺序</strong>：</p><ol><li>填 <strong>① 用户名</strong> 和 <strong>② 密码</strong>；</li><li>先勾选页面里 <strong>③ 人机验证</strong>（它在登录按钮的<strong>下方</strong>）；</li><li>再回到上面点 <strong>④ 登录</strong>。</li></ol><p>也可以点最下方的 <strong>使用 GitHub 继续</strong>，用 GitHub 账号一键登录。</p><div class="tip custom-block"><p class="custom-block-title">想找回密码？</p><p>登录页有「忘记密码」入口，但重置链接是发到邮箱的。如果你注册时没填邮箱，建议登录后到 <strong>个人资料</strong> 里绑定一个常用邮箱，方便日后找回。</p></div><h2 id="登录后-控制台概览" tabindex="-1">登录后：控制台概览 <a class="header-anchor" href="#登录后-控制台概览" aria-label="Permalink to &quot;登录后：控制台概览&quot;">​</a></h2><p>登录成功后默认进入 <strong>概览</strong> 页。最重要的是左上角的余额：</p><p><img src="'+o+'" alt="控制台概览：蓝框是当前余额，橙框是充值入口，紫框是公告和常见问答"></p><ul><li><strong>蓝框 当前余额（CNY）</strong>：调用模型时从这里扣费。<strong>余额为 0 时请求会失败</strong>，所以下一步通常是先充值。</li><li><strong>橙框 充值</strong>：点它直接进入充值页。</li><li><strong>紫框 公告 / 常见问答</strong>：版本更新、重要通知和高频问题都在这里，遇到问题先扫一眼。</li></ul><p>左侧是导航栏，常用的几个入口：</p><p><img src="'+g+'" alt="侧边栏：概览（总览与余额）、API 密钥（创建调用 Key）、使用日志（查看每次调用）、钱包（充值与余额）"></p><table tabindex="0"><thead><tr><th>侧边栏入口</th><th>作用</th></tr></thead><tbody><tr><td><strong>概览</strong></td><td>余额、公告、运行状态总览</td></tr><tr><td><strong>API 密钥</strong></td><td>创建给工具用的调用凭证（Key）</td></tr><tr><td><strong>使用日志</strong></td><td>查看每一次调用的模型、耗时和消耗</td></tr><tr><td><strong>钱包</strong></td><td>充值、查看余额和订单</td></tr></tbody></table><h2 id="接下来按顺序做" tabindex="-1">接下来按顺序做 <a class="header-anchor" href="#接下来按顺序做" aria-label="Permalink to &quot;接下来按顺序做&quot;">​</a></h2><p>注册和登录只是第一步。要让 Claude Code、Codex、Cherry Studio 这些工具真正能用，还要<strong>按顺序</strong>完成下面四步，跳过任何一步都会调用失败：</p><table tabindex="0"><thead><tr><th>顺序</th><th>操作</th><th>入口</th></tr></thead><tbody><tr><td>1</td><td>充值余额</td><td>侧边栏 → <strong>钱包</strong>　→ <a href="/guide/recharge">充值说明</a></td></tr><tr><td>2</td><td>创建 API 密钥</td><td>侧边栏 → <strong>API 密钥</strong>　→ <a href="/guide/create-key">创建专属 Key</a></td></tr><tr><td>3</td><td>复制模型名</td><td>顶部导航 → <strong>模型广场</strong></td></tr><tr><td>4</td><td>配置工具</td><td><a href="/guide/quick-start">快速接入</a></td></tr></tbody></table><h2 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h2><p><strong>注册页没有邮箱栏，正常吗？</strong></p><p>正常。默认注册只需要用户名和密码。只有站点开启邮箱验证时才会出现邮箱栏。</p><p><strong>人机验证一直转圈 / 点了没反应？</strong></p><p>刷新页面重试；如果用了网络代理/VPN，尝试关闭后再勾选。验证通过后方框会显示「人机验证已完成」。</p><p><strong>注册成功，但客户端还是不能用？</strong></p><p>注册只完成了第一步。还需要按顺序完成：<strong>充值 → 创建 Key → 复制模型名 → 配置工具</strong>。这四步里少做一步，工具都会报错。</p>',37)])])}const q=a(l,[["render",p]]);export{P as __pageData,q as default};
